**2. Context types and creation**

```typescript
type StepperContextType = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextType | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextType = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextType | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}
```

Notes:
- Two separate contexts following the same `createContext<T | null>(null)` + throwing hook pattern from `carousel.tsx` lines 33-43.
- `StepperContext` is the root-level context (analogous to `CarouselContext`).
- `StepperItemContext` is the item-level context (analogous to `FormItemContext` in `form.tsx` lines 72-74, but using null+throw instead of empty-object pattern for stricter safety).

**3. Stepper (root component)**

```typescript
function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
