"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

type StepperContextType = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextType | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextType = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextType | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()
  const state: StepperItemContextType["state"] =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "group/stepper-item flex items-center gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { state, step } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        "focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-none",
        "disabled:pointer-events-none disabled:opacity-50",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" && "border-primary bg-background text-primary",
        state === "pending" &&
          "border-muted-foreground/40 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (state === "completed" ? <CheckIcon className="size-4" /> : step)}
    </button>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation, activeStep } = useStepper()
  const { step } = useStepperItem()
  const isCompleted = step < activeStep

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "pending"}
      className={cn(
        "transition-colors",
        orientation === "horizontal" ? "h-0.5 flex-1" : "ml-4 w-0.5 flex-1",
        isCompleted ? "bg-primary" : "bg-border",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

